   * @param filters Search filters
   * @returns Promise resolving to an array of studies matching the filters
   */
  searchDoubleBlindStudies(filters: any): Promise<DoubleBlindStudy[]>;

  /**
   * Append an audit log entry to a double-blind study
   * @param studyId ID of the study
   * @param entry Audit log entry to append
   * @returns Promise resolving when the operation completes
   */
  appendDoubleBlindStudyAuditLog(studyId: string, entry: BlindingAuditLog): Promise<void>;

  /**
   * Store a block randomization sequence for a study
   * @param studyId ID of the study
   * @param blockNumber Block number
   * @param sequence The randomization sequence
   * @returns Promise resolving when the operation completes
   */
  storeBlockRandomizationSequence(studyId: string, blockNumber: number, sequence: string[]): Promise<void>;

  /**
   * Retrieve a block randomization sequence for a study
   * @param studyId ID of the study
   * @param blockNumber Block number
   * @returns The randomization sequence
   */
  getBlockRandomizationSequence(studyId: string, blockNumber: number): string[];

  /**
   * Store assignment counts for a stratum in a study
   * @param studyId ID of the study
   * @param stratumId Stratum identifier
   * @param counts Assignment counts per arm
   * @returns Promise resolving when the operation completes
   */
  storeStratumAssignmentCounts(studyId: string, stratumId: string, counts: Record<string, number>): Promise<void>;

  /**
   * Retrieve assignment counts for a stratum in a study
   * @param studyId ID of the study
   * @param stratumId Stratum identifier
   * @returns Assignment counts per arm, or null if not found
   */
  getStratumAssignmentCounts(studyId: string, stratumId: string): Record<string, number> | null;

  /**
   * Retrieve participant data
   * @param participantId ID of the participant
   * @returns Participant data
   */
  getParticipantData(participantId: string): Record<string, any>;

  /**
   * Get a single participant by ID
   * @param id The participant ID
   * @returns Promise resolving to the participant or null if not found
   */
  getParticipant(id: string): Promise<Record<string, any> | null>;

  /**
   * Get multiple participants by IDs
   * @param ids Array of participant IDs
   * @returns Promise resolving to an array of participants
   */
  getParticipants(ids: string[]): Promise<Record<string, any>[]>;

  /**
   * Query for participants based on criteria
   * @param criteria Query criteria
   * @param options Query options like pagination
   * @returns Promise resolving to participants matching the criteria
   */
  queryParticipants(criteria: any, options?: any): Promise<Record<string, any>[]>;

  /**
   * Export participant data in a specific format
   * @param participantIds IDs of participants to export
   * @param format Export format
   * @param fields Fields to include in export
   * @returns Promise resolving to export data
   */
  exportParticipantData(
    participantIds: string[],
    format: 'csv' | 'json' | 'xlsx',
    fields?: string[]
  ): Promise<any>;

  /**
   * Save a grant proposal to the data store
   * @param proposal The proposal to save
   * @returns Promise resolving when the operation completes
   */
  saveProposal(proposal: GrantProposal): Promise<void>;

  /**
   * Retrieve a grant proposal by ID
   * @param proposalId ID of the proposal to retrieve
   * @returns Promise resolving to the proposal or null if not found
   */
  getProposal(proposalId: string): Promise<GrantProposal | null>;

  /**
   * Delete a grant proposal
   * @param proposalId ID of the proposal to delete
   * @returns Promise resolving when the operation completes
   */
  deleteProposal(proposalId: string): Promise<void>;

  /**
   * Search for grant proposals based on filters
   * @param filters Search filters
   * @returns Promise resolving to an array of proposals matching the filters
   */
  searchProposals(filters: any): Promise<GrantProposal[]>;

  /**
   * Retrieve a funding body by ID
   * @param fundingBodyId ID of the funding body to retrieve
   * @returns Promise resolving to the funding body or null if not found
   */
  getFundingBody(fundingBodyId: string): Promise<FundingBody | null>;

  /**
   * Retrieve a funding scheme by ID
   * @param fundingSchemeId ID of the funding scheme to retrieve
   * @returns Promise resolving to the funding scheme or null if not found
   */
  getFundingScheme(fundingSchemeId: string): Promise<FundingScheme | null>;

  /**
   * Search for funding schemes based on filters
   * @param filters Search filters
   * @returns Promise resolving to an array of funding schemes matching the filters
   */
  searchFundingSchemes(filters: any): Promise<FundingScheme[]>;
}

/**
 * Data Sharing Models
 * 
 * This file defines the data structures for cross-institutional data sharing
 * within the EdPsych Research Foundation, including agreements, datasets,
 * sharing requests, and access controls.
 */

import { v4 as uuidv4 } from 'uuid';

/**
 * Status of a data sharing agreement
 */
export enum AgreementStatus {
  DRAFT = 'draft',
  PENDING_APPROVAL = 'pending_approval',
  ACTIVE = 'active',
  EXPIRED = 'expired',
  TERMINATED = 'terminated',
  REJECTED = 'rejected'
}

/**
 * Status of a data sharing request
 */
export enum SharingRequestStatus {
  DRAFT = 'draft',
  SUBMITTED = 'submitted',
  UNDER_REVIEW = 'under_review',
  APPROVED = 'approved',
  REJECTED = 'rejected',
  WITHDRAWN = 'withdrawn',
  EXPIRED = 'expired'
}

/**
 * Access level for shared data
 */
export enum DataAccessLevel {
  METADATA_ONLY = 'metadata_only',        // Only descriptive information about the dataset
  AGGREGATED_RESULTS = 'aggregated_results', // Only aggregated/statistical results
  SYNTHETIC = 'synthetic',               // Synthetic data derived from original
  ANONYMIZED = 'anonymized',             // Fully anonymized data
  PSEUDONYMIZED = 'pseudonymized',       // Pseudonymized data
  IDENTIFIED = 'identified'              // Data with identifiers (requires highest level of protection)
}

/**
 * Type of dataset being shared
 */
export enum DatasetType {
  SURVEY_RESPONSES = 'survey_responses',
  ASSESSMENT_RESULTS = 'assessment_results',
  OBSERVATIONAL_DATA = 'observational_data',
  INTERVIEW_TRANSCRIPTS = 'interview_transcripts',
  NEUROPSYCHOLOGICAL_TESTS = 'neuropsychological_tests',
  BEHAVIORAL_METRICS = 'behavioral_metrics',
  EDUCATIONAL_OUTCOMES = 'educational_outcomes',
  DEMOGRAPHIC_DATA = 'demographic_data',
  LONGITUDINAL_TRACKING = 'longitudinal_tracking',
  INTERVENTION_OUTCOMES = 'intervention_outcomes',
  SOCIAL_NETWORK_ANALYSIS = 'social_network_analysis',
  MIXED_METHODS = 'mixed_methods'
}

/**
 * Usage purpose for shared data
 */
export enum DataUsagePurpose {
  ACADEMIC_RESEARCH = 'academic_research',
  EDUCATIONAL_IMPROVEMENT = 'educational_improvement',
  POLICY_DEVELOPMENT = 'policy_development',
  PRODUCT_DEVELOPMENT = 'product_development',
  PROGRAM_EVALUATION = 'program_evaluation',
  META_ANALYSIS = 'meta_analysis',
  MACHINE_LEARNING_TRAINING = 'machine_learning_training',
  BENCHMARKING = 'benchmarking',
  REPLICATION_STUDY = 'replication_study',
  VALIDATION_STUDY = 'validation_study'
}

/**
 * Data format for shared data
 */
export enum DataFormat {
  CSV = 'csv',
  JSON = 'json',
  XML = 'xml',
  PARQUET = 'parquet',
  AVRO = 'avro',
  SQL = 'sql',
  RDF = 'rdf',
  EXCEL = 'excel',
  SPSS = 'spss',
  STATA = 'stata',
  R_DATA = 'r_data',
  PYTHON_PICKLE = 'python_pickle',
  CUSTOM = 'custom'
}

/**
 * Legal basis for data processing under GDPR and similar regulations
 */
export enum LegalBasis {
  CONSENT = 'consent',
  CONTRACT = 'contract',
  LEGAL_OBLIGATION = 'legal_obligation',
  VITAL_INTERESTS = 'vital_interests',
  PUBLIC_TASK = 'public_task',
  LEGITIMATE_INTERESTS = 'legitimate_interests',
  SCIENTIFIC_RESEARCH = 'scientific_research'
}

/**
 * Represents a field in a dataset
 */
export interface DataField {
  id: string;
  name: string;
  description: string;
  dataType: string; // String, Number, Date, Boolean, etc.
  isIdentifiable: boolean;
  isPHI: boolean; // Protected Health Information
  isRequired: boolean;
  possibleValues?: string[];
  unitOfMeasure?: string;
  validationRules?: string[];
  sensitivityLevel: 'low' | 'medium' | 'high' | 'critical';
}

/**
 * Data protection measures applied to a dataset
 */
export interface DataProtectionMeasures {
  anonymizationTechniques?: string[];
  encryptionMethods?: string[];
  accessControls: string[];
  dataMinimizationApplied: boolean;
  retentionPeriod?: number; // In months
  additionalMeasures?: string[];
}

/**
 * Represents a dataset that can be shared
 */
export interface SharedDataset {
  id: string;
  name: string;
  description: string;
  ownerId: string; // Institution ID
  createdBy: string; // User ID
  createdDate: Date;
  lastUpdated: Date;
  updatedBy: string;
  type: DatasetType;
  subtype?: string;
  accessLevel: DataAccessLevel;
  fields: DataField[];
  dataFormat: DataFormat;
  sampleDataUrl?: string;
  dataProtection: DataProtectionMeasures;
  ethicsApprovalId?: string;
  dataRetentionPeriod: number; // In months
  containsMinorData: boolean;
  containsSensitiveData: boolean;
  containsSpecialCategoryData: boolean; // GDPR special categories
  metadata: Record<string, any>;
  tags: string[];
  size?: number; // In bytes
  recordCount?: number;
  timeframe?: {
    startDate: Date;
    endDate: Date;
  };
  version: string;
  isActive: boolean;
  deactivationReason?: string;
  deactivationDate?: Date;
}

/**
 * Represents a data sharing agreement between institutions
 */
export interface DataSharingAgreement {
  id: string;
  name: string;
  description: string;
  createdBy: string;
  createdDate: Date;
  lastUpdated: Date;
  updatedBy: string;
  status: AgreementStatus;
  startDate: Date;
  endDate: Date;
  providerInstitutionId: string;
  recipientInstitutions: string[]; // Institution IDs
  sharedDatasets: string[]; // Dataset IDs
  allowedPurposes: DataUsagePurpose[];
  legalBasis: LegalBasis;
  dataProtectionClauses: string[];
  intellectualPropertyClauses: string[];
  confidentialityClauses: string[];
  liabilityClauses: string[];
  breachNotificationProcedure: string;
  disputeResolutionProcedure: string;
  terminationClauses: string[];
  governingLaw: string;
  documentUrl?: string;
  signedDocumentUrl?: string;
  approvals: {
    id: string;
    approvedBy: string;
    approvalDate: Date;
    comments?: string;
  }[];
  rejections?: {
    id: string;
    rejectedBy: string;
    rejectionDate: Date;
    reason: string;
  }[];
  renewalDate: Date;
  renewedBy: string;
  previousEndDate: Date;
  newEndDate: Date;
  changes?: string;
  amendments?: {
    amendmentDate: Date;
    amendedBy: string;
    description: string;
    documentUrl?: string;
  }[];
  isActive: boolean;
  terminationReason?: string;
  terminationDate?: Date;
  terminatedBy?: string;
}

/**
 * Represents a request to access shared data
 */
export interface DataSharingRequest {
  id: string;
  title: string;
  description: string;
  requestingInstitutionId: string;
  requestedDatasets: string[]; // Dataset IDs
  dataProviderInstitutionId: string;
  requestingUserId: string;
  requestDate: Date;
  status: SharingRequestStatus;
  researchPurpose: DataUsagePurpose;
  projectDescription: string;
  researchQuestions: string[];
  methodologySummary: string;
  proposedAnalysisMethods: string[];
  expectedOutputs: string[];
  requestedAccessLevel: DataAccessLevel;
  requestedFields?: string[]; // Specific fields requested
  requestedDuration: number; // In months
  ethicsApprovalId?: string;
  ethicsApprovalDocumentUrl?: string;
  dataManagementPlanUrl?: string;
  reviewers?: string[]; // User IDs
  reviewComments?: {
    reviewerId: string;
    comment: string;
    timestamp: Date;
  }[];
  reviewDecision?: {
    decision: 'approved' | 'rejected' | 'more_info_needed';
    decidedBy: string;
    decisionDate: Date;
    rationale: string;
    conditions?: string[];
  };
  expiryDate?: Date;
  isActive: boolean;
  withdrawalReason?: string;
  withdrawalDate?: Date;
}

/**
 * Represents an access grant for shared data
 */
export interface DataAccessGrant {
  id: string;
  requestId: string;
  grantedBy: string;
  grantDate: Date;
  expiryDate: Date;
  institutionId: string;
  userId: string;
  datasetIds: string[];
  accessLevel: DataAccessLevel;
  accessibleFields?: string[]; // Field IDs, if subset
  ipRestrictions?: string[];
  timeRestrictions?: {
    startTime: string; // HH:MM
    endTime: string; // HH:MM
    timezone: string;
    allowedDays: ('mon' | 'tue' | 'wed' | 'thu' | 'fri' | 'sat' | 'sun')[];
  };
  usageConditions: string[];
  accessCredentials?: {
    apiKey?: string;
    tokenExpiry?: Date;
    encryptionKey?: {
      publicKey: string;
      algorithm: string;
    };
  };
  auditRequirements: {
    logAccessAttempts: boolean;
    logDataRetrievals: boolean;
    periodicAuditReview: boolean;
    auditReviewFrequency?: number; // In days
  };
  isActive: boolean;
  revocationReason?: string;
  revocationDate?: Date;
  revokedBy?: string;
}

/**
 * Audit record for data sharing activities
 */
export interface DataSharingAuditLog {
  id: string;
  timestamp: Date;
  action: 'data_request' | 'data_access' | 'agreement_created' | 'agreement_signed' |
         'access_granted' | 'access_revoked' | 'data_downloaded' | 'data_viewed' |
         'query_executed' | 'api_access';
  userId: string;
  institutionId: string;
  resourceId: string; // Agreement ID, Dataset ID, etc.
  resourceType: 'agreement' | 'dataset' | 'request' | 'access_grant';
  details: Record<string, any>;
  ipAddress?: string;
  userAgent?: string;
  success: boolean;
  failureReason?: string;
}

/**
 * Create a new shared dataset
 */
export function createSharedDataset(
  params: {
    name: string;
    description: string;
    ownerId: string;
    type: DatasetType;
    accessLevel: DataAccessLevel;
    fields: Omit<DataField, 'id'>[];
    dataFormat: DataFormat;
    dataProtection: DataProtectionMeasures;
    dataRetentionPeriod: number;
    containsMinorData: boolean;
    containsSensitiveData: boolean;
    containsSpecialCategoryData: boolean;
    metadata?: Record<string, any>;
    tags?: string[];
    size?: number;
    recordCount?: number;
    timeframe?: {
      startDate: Date;
      endDate: Date;
    };
    version?: string;
  },
  createdBy: string
): SharedDataset {
  const now = new Date();
  
  const fields = params.fields.map(field => ({
    ...field,
    id: uuidv4()
  }));
  
  return {
    id: uuidv4(),
    name: params.name,
    description: params.description,
    ownerId: params.ownerId,
    createdBy,
    createdDate: now,
    lastUpdated: now,
    updatedBy: createdBy,
    type: params.type,
    accessLevel: params.accessLevel,
    fields,
    dataFormat: params.dataFormat,
    dataProtection: params.dataProtection,
    dataRetentionPeriod: params.dataRetentionPeriod,
    containsMinorData: params.containsMinorData,
    containsSensitiveData: params.containsSensitiveData,
    containsSpecialCategoryData: params.containsSpecialCategoryData,
    metadata: params.metadata || {},
    tags: params.tags || [],
    size: params.size,
    recordCount: params.recordCount,
    timeframe: params.timeframe,
    version: params.version || '1.0.0',
    isActive: true
  };
}

/**
 * Create a new data sharing agreement
 */
export function createDataSharingAgreement(
  params: {
    name: string;
    description: string;
    startDate: Date;
    endDate: Date;
    providerInstitutionId: string;
    recipientInstitutions: string[];
    sharedDatasets: string[];
    allowedPurposes: DataUsagePurpose[];
    legalBasis: LegalBasis;
    dataProtectionClauses: string[];
    intellectualPropertyClauses: string[];
    confidentialityClauses: string[];
    liabilityClauses: string[];
    breachNotificationProcedure: string;
    disputeResolutionProcedure: string;
    terminationClauses: string[];
    governingLaw: string;
    documentUrl?: string;
    status?: AgreementStatus;
  },
  createdBy: string
): DataSharingAgreement {
  const now = new Date();
  
  return {
    id: uuidv4(),
    name: params.name,
    description: params.description,
    createdBy,
    createdDate: now,
    lastUpdated: now,
    updatedBy: createdBy,
    status: params.status || AgreementStatus.DRAFT,
    startDate: params.startDate,
    endDate: params.endDate,
    providerInstitutionId: params.providerInstitutionId,
    recipientInstitutions: params.recipientInstitutions,
    sharedDatasets: params.sharedDatasets,
    allowedPurposes: params.allowedPurposes,
    legalBasis: params.legalBasis,
    dataProtectionClauses: params.dataProtectionClauses,
    intellectualPropertyClauses: params.intellectualPropertyClauses,
    confidentialityClauses: params.confidentialityClauses,
    liabilityClauses: params.liabilityClauses,
    breachNotificationProcedure: params.breachNotificationProcedure,
    disputeResolutionProcedure: params.disputeResolutionProcedure,
    terminationClauses: params.terminationClauses,
    governingLaw: params.governingLaw,
    documentUrl: params.documentUrl,
    approvals: [],
    isActive: true,
    signedDocumentUrl: undefined,
    rejections: undefined,
    renewals: undefined,
    amendments: undefined,
    terminationReason: undefined,
    terminationDate: undefined,
    terminatedBy: undefined
  };
}

/**
 * Create a new data sharing request
 */
export function createDataSharingRequest(
  params: {
    title: string;
    description: string;
    requestingInstitutionId: string;
    requestedDatasets: string[];
    dataProviderInstitutionId: string;
    researchPurpose: DataUsagePurpose;
    projectDescription: string;
    researchQuestions: string[];
    methodologySummary: string;
    proposedAnalysisMethods: string[];
    expectedOutputs: string[];
    requestedAccessLevel: DataAccessLevel;
    requestedFields?: string[];
    requestedDuration: number;
    ethicsApprovalId?: string;
    ethicsApprovalDocumentUrl?: string;
    dataManagementPlanUrl?: string;
  },
  requestingUserId: string
): DataSharingRequest {
  const now = new Date();
  
  return {
    id: uuidv4(),
    title: params.title,
    description: params.description,
    requestingInstitutionId: params.requestingInstitutionId,
    requestedDatasets: params.requestedDatasets,
    dataProviderInstitutionId: params.dataProviderInstitutionId,
    requestingUserId,
    requestDate: now,
    status: SharingRequestStatus.DRAFT,
    researchPurpose: params.researchPurpose,
    projectDescription: params.projectDescription,
    researchQuestions: params.researchQuestions,
    methodologySummary: params.methodologySummary,
    proposedAnalysisMethods: params.proposedAnalysisMethods,
    expectedOutputs: params.expectedOutputs,
    requestedAccessLevel: params.requestedAccessLevel,
    requestedFields: params.requestedFields,
    requestedDuration: params.requestedDuration,
    ethicsApprovalId: params.ethicsApprovalId,
    ethicsApprovalDocumentUrl: params.ethicsApprovalDocumentUrl,
    dataManagementPlanUrl: params.dataManagementPlanUrl,
    isActive: true
  };
}

/**
 * Institution Models
 * 
 * This file defines the data structures for institutions participating in
 * cross-institutional data sharing within the EdPsych Research Foundation.
 */

import { v4 as uuidv4 } from 'uuid';

/**
 * Types of institutions that can participate in data sharing
 */
export enum InstitutionType {
  UNIVERSITY = 'university',
  RESEARCH_INSTITUTE = 'research_institute',
  GOVERNMENT_AGENCY = 'government_agency',
  HEALTHCARE_PROVIDER = 'healthcare_provider',
  SCHOOL_DISTRICT = 'school_district',
  EDUCATION_AUTHORITY = 'education_authority',
  NONPROFIT_ORGANIZATION = 'nonprofit_organization',
  COMMERCIAL_ENTITY = 'commercial_entity'
}

/**
 * Verification status for an institution
 */
export enum VerificationStatus {
  PENDING = 'pending',
  VERIFIED = 'verified',
  REJECTED = 'rejected',
  SUSPENDED = 'suspended'
}

/**
 * Compliance framework that an institution adheres to
 */
export enum ComplianceFramework {
  GDPR = 'gdpr',
  CCPA = 'ccpa',
  HIPAA = 'hipaa',
  FERPA = 'ferpa',
  UK_DPA = 'uk_data_protection_act',
  PIPEDA = 'pipeda',
  ISO_27001 = 'iso_27001',
  NIST = 'nist_cybersecurity',
  INTERNAL_IRB = 'internal_irb',
  EXTERNAL_IRB = 'external_irb'
}

/**
 * Address information for an institution
 */
export interface InstitutionAddress {
  street: string;
  city: string;
  state?: string;
  postalCode: string;
  country: string;
}

/**
 * Contact person for an institution
 */
export interface InstitutionContact {
  id: string;
  name: string;
  title: string;
  email: string;
  phone?: string;
  isPrimary: boolean;
  isDPO: boolean; // Data Protection Officer under GDPR
}

/**
 * Compliance certification for an institution
 */
export interface ComplianceCertification {
  id: string;
  framework: ComplianceFramework;
  certificationId?: string;
  issuingAuthority?: string;
  issueDate: Date;
  expiryDate?: Date;
  documentationUrl?: string;
  verificationStatus: VerificationStatus;
  verifiedBy?: string;
  verificationDate?: Date;
}

/**
 * Data governance policy for an institution
 */
export interface DataGovernancePolicy {
  id: string;
  title: string;
  description: string;
  documentUrl: string;
  version: string;
  effectiveDate: Date;
  approvedBy: string;
  lastReviewDate: Date;
  nextReviewDate: Date;
}

/**
 * Main institution record
 */
export interface Institution {
  id: string;
  name: string;
  shortName?: string;
  type: InstitutionType;
  description: string;
  website: string;
  registrationNumber?: string; // Official registration/business number
  taxId?: string;
  address: InstitutionAddress;
  contacts: InstitutionContact[];
  verificationStatus: VerificationStatus;
  verificationDate?: Date;
  verifiedBy?: string;
  registrationDate: Date;
  lastUpdated: Date;
  updatedBy: string;
  complianceCertifications: ComplianceCertification[];
  dataGovernancePolicies: DataGovernancePolicy[];
  supportedDataFormats: string[]; // MIME types or format identifiers
  apiEndpoint?: string; // For automated data exchange
  publicKey?: string; // For encrypted data exchange
  
  // Institutional capabilities
  hasEthicsCommittee: boolean;
  hasDataProtectionOfficer: boolean;
  hasTechnicalInfrastructure: boolean;
  
  // Additional metadata
  metadata: Record<string, any>;
  
  // Audit and administrative
  isActive: boolean;
  deactivationReason?: string;
  deactivationDate?: Date;
}

/**
 * Parameters to create a new institution
 */
export interface InstitutionCreationParams {
  name: string;
  shortName?: string;
  type: InstitutionType;
  description: string;
  website: string;
  registrationNumber?: string;
  taxId?: string;
  address: InstitutionAddress;
  primaryContact: Omit<InstitutionContact, 'id' | 'isPrimary'>;
  supportedDataFormats: string[];
  hasEthicsCommittee: boolean;
  hasDataProtectionOfficer: boolean;
  hasTechnicalInfrastructure: boolean;
  metadata?: Record<string, any>;
}

/**
 * Create a new institution entity
 */
export function createInstitution(params: InstitutionCreationParams, createdBy: string): Institution {
  const now = new Date();
  
  // Create primary contact
  const primaryContact: InstitutionContact = {
    id: uuidv4(),
    name: params.primaryContact.name,
    title: params.primaryContact.title,
    email: params.primaryContact.email,
    phone: params.primaryContact.phone,
    isPrimary: true,
    isDPO: params.primaryContact.isDPO
  };
  
  return {
    id: uuidv4(),
    name: params.name,
    shortName: params.shortName,
    type: params.type,
    description: params.description,
    website: params.website,
    registrationNumber: params.registrationNumber,
    taxId: params.taxId,
    address: params.address,
    contacts: [primaryContact],
    verificationStatus: VerificationStatus.PENDING,
    registrationDate: now,
    lastUpdated: now,
    updatedBy: createdBy,
    complianceCertifications: [],
    dataGovernancePolicies: [],
    supportedDataFormats: params.supportedDataFormats,
    hasEthicsCommittee: params.hasEthicsCommittee,
    hasDataProtectionOfficer: params.hasDataProtectionOfficer,
    hasTechnicalInfrastructure: params.hasTechnicalInfrastructure,
    metadata: params.metadata || {},
    isActive: true
  };
}

/**
 * Data Sharing Service
 * 
 * This service handles the management of cross-institutional data sharing,
 * including agreements, requests, and access grants.
 */

import { 
   
  DataSharingAgreement, 
  DataSharingRequest, 
  DataAccessGrant,
  DataAccessLevel, 
  DataUsagePurpose,
  AgreementStatus,
  SharingRequestStatus,
  LegalBasis,
  createDataSharingAgreement,
  createDataSharingRequest
} from '../models/data-sharing';
import { Institution, VerificationStatus } from '../models/institution';
import { InstitutionService } from './institution-service';
import { DataAccessService } from '../../data-lake/services/data-access-service';
import { GovernanceService } from '../../governance/services/governance-service';
import { EventBusService } from '../../shared/services/event-bus';
import { LoggingService } from '../../shared/services/logging-service';
import { v4 as uuidv4 } from 'uuid';

/**
 * Status for data access grants
 */
export enum GrantStatus {
  PENDING = 'pending',
  ACTIVE = 'active',
  EXPIRED = 'expired',
  REVOKED = 'revoked'
}

/**
 * Days of week type for time restrictions
 */
export type DayOfWeek = 'mon' | 'tue' | 'wed' | 'thu' | 'fri' | 'sat' | 'sun';

/**
 * Data Sharing Service error types
 */
export type DataSharingErrorType = 
  | 'INVALID_INSTITUTION' 
  | 'INSUFFICIENT_COMPLIANCE' 
  | 'UNAUTHORIZED_ACCESS'
  | 'AGREEMENT_VIOLATION'
  | 'EXPIRED_AGREEMENT'
  | 'EXPIRED_CERTIFICATION'
  | 'INVALID_REQUEST'
  | 'INVALID_DATASET'
  | 'INVALID_ACCESS_LEVEL'
  | 'GOVERNANCE_VIOLATION';

/**
 * Data Sharing Service error
 */
export class DataSharingError extends Error {
  constructor(
    public type: DataSharingErrorType,
    message: string,
    public details?: Record<string, any>
  ) {
    super(message);
    this.name = 'DataSharingError';
  }
}

/**
 * Create a data access grant
 */
export function createDataAccessGrant(
  params: {
    requestId: string;
    agreementId: string;
    datasetIds: string[];
    accessLevel: DataAccessLevel;
    purpose: DataUsagePurpose;
    status: GrantStatus;
    approverId: string;
    approverNotes?: string;
    expiryDate: Date;
    accessibleFields?: string[];
    ipRestrictions?: string[];
    timeRestrictions?: {
      startTime: string;
      endTime: string;
      timezone: string;
      allowedDays: DayOfWeek[];
    };
    usageConditions?: string[];
  }
): DataAccessGrant {
  const now = new Date();
  
  return {
    id: uuidv4(),
    requestId: params.requestId,
    grantedBy: params.approverId,
    grantDate: now,
    expiryDate: params.expiryDate,
    institutionId: '', // Will be filled by the service
    userId: params.approverId,
    datasetIds: params.datasetIds,
    accessLevel: params.accessLevel,
    accessibleFields: params.accessibleFields,
    ipRestrictions: params.ipRestrictions,
    timeRestrictions: params.timeRestrictions,
    usageConditions: params.usageConditions || [],
    auditRequirements: {
      logAccessAttempts: true,
      logDataRetrievals: true,
      periodicAuditReview: true
    },
    isActive: true
  };
}

/**
 * Data Sharing Service for managing cross-institutional data sharing
 */
export class DataSharingService {
  private logger: LoggingService;

  constructor(
    private _institutionService: InstitutionService,
    private dataAccessService: DataAccessService,
    private governanceService: GovernanceService,
    private eventBus: EventBusService,
    logger?: LoggingService
  ) {
    this.logger = logger || new LoggingService();
  }

  /**
   * Create a new data sharing agreement between institutions
   */
  async createAgreement(
    _providerId: string,
    _recipientIds: string[],
    _datasetIds: string[],
    allowedPurposes: DataUsagePurpose[],
    allowedAccessLevels: DataAccessLevel[],
    startDate: Date,
    endDate: Date,
    termsAndConditions: string,
    legalBasis: LegalBasis,
    createdById: string,
    name: string,
    description: string
  ): Promise<DataSharingAgreement> {
    // Verify institutions exist and are verified
    const provider = await this.getVerifiedInstitution(_providerId);
    
    for (const recipientId of _recipientIds) {
      await this.getVerifiedInstitution(recipientId);
    }

    // Verify datasets exist and provider has rights to share them
    const datasets = await Promise.all(
      _datasetIds.map(async (datasetId) => {
        const dataset = await this.dataAccessService.getDatasetById(datasetId);
        if (!dataset) {
          throw new DataSharingError(
            'INVALID_DATASET',
            `Dataset with ID ${datasetId} does not exist`,
            { datasetId }
          );
        }
        
        // Check if provider has rights to share this dataset
        const hasRights = await this.hasDatasetRights(_providerId, datasetId);
        if (!hasRights) {
          throw new DataSharingError(
            'UNAUTHORIZED_ACCESS',
            `Institution ${_providerId} does not have rights to share dataset ${datasetId}`,
            { _providerId, datasetId }
          );
        }
        
        return dataset;
      })
    );

    // Check governance policies for data sharing
    const governanceCheck = await this.checkDataSharingCompliance(
      _providerId,
      _recipientIds,
      _datasetIds,
      allowedAccessLevels,
      allowedPurposes
    );

    if (!governanceCheck.compliant) {
      throw new DataSharingError(
        'GOVERNANCE_VIOLATION',
        `Data sharing violates governance policies: ${governanceCheck.reasons.join(', ')}`,
        { _providerId, _recipientIds, violations: governanceCheck.reasons }
      );
    }

    // Create the agreement
    const agreement = createDataSharingAgreement({
      name,
      description,
      startDate,
      endDate,
      providerInstitutionId: _providerId,
      recipientInstitutions: _recipientIds,
      sharedDatasets: _datasetIds,
      allowedPurposes: allowedPurposes,
      legalBasis,
      dataProtectionClauses: [termsAndConditions],
      intellectualPropertyClauses: [],
      confidentialityClauses: [],
      liabilityClauses: [],
      breachNotificationProcedure: '',
      disputeResolutionProcedure: '',
      terminationClauses: [],
      governingLaw: 'United Kingdom',
      status: AgreementStatus.PENDING_APPROVAL
    }, createdById);

    // Save the agreement
    await this.dataAccessService.saveAgreement(agreement);

    // Log the creation
    this.logger.info('Data sharing agreement created', {
      agreementId: agreement.id,
      _providerId,
      _recipientIds,
      datasetIds: _datasetIds
    });

    // Publish event
    this.eventBus.emit('dataSharingAgreement.created', {
      agreement,
      provider,
      _recipientIds,
      datasets
    });

    return agreement;
  }

  /**
   * Update an existing data sharing agreement
   */
  async updateAgreement(
    agreementId: string,
    updates: Partial<Omit<DataSharingAgreement, 'id' | 'providerInstitutionId' | 'recipientInstitutions'>>,
    updatedById: string
  ): Promise<DataSharingAgreement> {
    const agreement = await this.dataAccessService.getAgreementById(agreementId);
    if (!agreement) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} does not exist`,
        { agreementId }
      );
    }

    // If access levels or purposes are being updated, verify governance compliance
    if (updates.allowedPurposes || updates.sharedDatasets) {
      const sharedDatasets = updates.sharedDatasets || agreement.sharedDatasets;
      const allowedPurposes = updates.allowedPurposes || agreement.allowedPurposes;
      const allowedAccessLevels = agreement.allowedPurposes as unknown as DataAccessLevel[];
      
      const governanceCheck = await this.checkDataSharingCompliance(
        agreement.providerInstitutionId,
        agreement.recipientInstitutions,
        sharedDatasets,
        allowedAccessLevels,
        allowedPurposes
      );

      if (!governanceCheck.compliant) {
        throw new DataSharingError(
          'GOVERNANCE_VIOLATION',
          `Updated agreement violates governance policies: ${governanceCheck.reasons.join(', ')}`,
          { agreementId, violations: governanceCheck.reasons }
        );
      }
    }

    // Apply updates
    const updatedAgreement = {
      ...agreement,
      ...updates,
      updatedBy: updatedById,
      lastUpdated: new Date()
    };

    // Save the updated agreement
    await this.dataAccessService.updateAgreement(updatedAgreement);

    // Log the update
    this.logger.info('Data sharing agreement updated', {
      agreementId,
      updates: Object.keys(updates)
    });

    // Publish event
    this.eventBus.emit('dataSharingAgreement.updated', {
      previous: agreement,
      current: updatedAgreement
    });

    return updatedAgreement;
  }

  /**
   * Activate a pending data sharing agreement
   */
  async activateAgreement(agreementId: string, activatedById: string): Promise<DataSharingAgreement> {
    const agreement = await this.dataAccessService.getAgreementById(agreementId);
    if (!agreement) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} does not exist`,
        { agreementId }
      );
    }

    if (agreement.status !== AgreementStatus.PENDING_APPROVAL) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} is not in PENDING_APPROVAL status`,
        { agreementId, currentStatus: agreement.status }
      );
    }

    // Verify both institutions still exist and are verified
    const provider = await this.getVerifiedInstitution(agreement.providerInstitutionId);
    
    for (const recipientId of agreement.recipientInstitutions) {
      await this.getVerifiedInstitution(recipientId);
    }

    // Verify provider has active compliance certifications
    const providerCompliance = await this.getComplianceStatus(agreement.providerInstitutionId);
    if (!providerCompliance.compliant) {
      throw new DataSharingError(
        'INSUFFICIENT_COMPLIANCE',
        `Provider institution does not have required compliance certifications: ${providerCompliance.reasons.join(', ')}`,
        { id: agreement.providerInstitutionId, reasons: providerCompliance.reasons }
      );
    }

    // Verify all recipients have active compliance certifications
    for (const recipientId of agreement.recipientInstitutions) {
      const recipientCompliance = await this.getComplianceStatus(recipientId);
      if (!recipientCompliance.compliant) {
        throw new DataSharingError(
          'INSUFFICIENT_COMPLIANCE',
          `Recipient institution ${recipientId} does not have required compliance certifications: ${recipientCompliance.reasons.join(', ')}`,
          { id: recipientId, reasons: recipientCompliance.reasons }
        );
      }
    }

    // Create activation approval
    const approval = {
      id: agreement.providerInstitutionId,
      approvedBy: activatedById,
      approvalDate: new Date(),
      comments: 'Agreement activated'
    };

    // Update the agreement status
    const activatedAgreement = await this.updateAgreement(agreementId, {
      status: AgreementStatus.ACTIVE,
      approvals: [...(agreement.approvals || []), approval]
    }, activatedById);

    // Log the activation
    this.logger.info('Data sharing agreement activated', {
      agreementId,
      providerId: agreement.providerInstitutionId,
      recipientIds: agreement.recipientInstitutions
    });

    // Publish event
    this.eventBus.emit('dataSharingAgreement.activated', {
      agreement: activatedAgreement,
      provider,
      recipientIds: agreement.recipientInstitutions
    });

    return activatedAgreement;
  }

  /**
   * Terminate an active data sharing agreement
   */
  async terminateAgreement(
    agreementId: string, 
    reason: string,
    terminatedById: string
  ): Promise<DataSharingAgreement> {
    const agreement = await this.dataAccessService.getAgreementById(agreementId);
    if (!agreement) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} does not exist`,
        { agreementId }
      );
    }

    if (agreement.status !== AgreementStatus.ACTIVE) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} is not in ACTIVE status`,
        { agreementId, currentStatus: agreement.status }
      );
    }

    // Revoke all active grants under this agreement
    const activeGrants = await this.getActiveGrantsByAgreement(agreementId);
    await Promise.all(
      activeGrants.map(grant => 
        this.revokeAccess(grant.id, `Agreement terminated: ${reason}`, terminatedById)
      )
    );

    // Update the agreement status
    const terminatedAgreement = await this.updateAgreement(agreementId, {
      status: AgreementStatus.TERMINATED,
      terminatedBy: terminatedById,
      terminationReason: reason,
      terminationDate: new Date()
    }, terminatedById);

    // Log the termination
    this.logger.info('Data sharing agreement terminated', {
      agreementId,
      reason,
      activeGrantsRevoked: activeGrants.length
    });

    // Publish event
    this.eventBus.emit('dataSharingAgreement.terminated', {
      agreement: terminatedAgreement,
      reason,
      revokedGrants: activeGrants
    });

    return terminatedAgreement;
  }

  /**
   * Submit a data access request
   */
  async requestDataAccess(
    recipientId: string,
    agreementId: string,
    _datasetIds: string[],
    accessLevel: DataAccessLevel,
    purpose: DataUsagePurpose,
    requestingUserId: string,
    projectDescription: string,
    researchQuestions: string[],
    methodologySummary: string,
    proposedAnalysisMethods: string[],
    expectedOutputs: string[],
    requestedDuration: number, // in months
    title: string,
    description: string
  ): Promise<DataSharingRequest> {
    // Verify the agreement exists and is active
    const agreement = await this.dataAccessService.getAgreementById(agreementId);
    if (!agreement) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} does not exist`,
        { agreementId }
      );
    }

    if (agreement.status !== AgreementStatus.ACTIVE) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Agreement with ID ${agreementId} is not active`,
        { agreementId, status: agreement.status }
      );
    }

    // Verify recipient is included in the agreement
    if (!agreement.recipientInstitutions.includes(recipientId)) {
      throw new DataSharingError(
        'UNAUTHORIZED_ACCESS',
        `Institution ${recipientId} is not a recipient in agreement ${agreementId}`,
        { recipientId, agreementRecipientIds: agreement.recipientInstitutions }
      );
    }

    // Verify datasets are included in the agreement
    for (const datasetId of _datasetIds) {
      if (!agreement.sharedDatasets.includes(datasetId)) {
        throw new DataSharingError(
          'INVALID_REQUEST',
          `Dataset ${datasetId} is not included in agreement ${agreementId}`,
          { datasetId, agreementId }
        );
      }
    }

    // Verify purpose is allowed by the agreement
    if (!agreement.allowedPurposes.includes(purpose)) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Purpose ${purpose} is not allowed by agreement ${agreementId}`,
        { purpose, allowedPurposes: agreement.allowedPurposes }
      );
    }

    // Create the request
    const request = createDataSharingRequest({
      title,
      description,
      requestingInstitutionId: recipientId,
      requestedDatasets: _datasetIds,
      dataProviderInstitutionId: agreement.providerInstitutionId,
      researchPurpose: purpose,
      projectDescription,
      researchQuestions,
      methodologySummary,
      proposedAnalysisMethods,
      expectedOutputs,
      requestedAccessLevel: accessLevel,
      requestedDuration
    }, requestingUserId);

    // Update status to submitted (as createDataSharingRequest defaults to DRAFT)
    const submittedRequest = {
      ...request,
      status: SharingRequestStatus.SUBMITTED
    };

    // Save the request
    await this.dataAccessService.saveRequest(submittedRequest);

    // Log the request
    this.logger.info('Data sharing request submitted', {
      requestId: submittedRequest.id,
      agreementId,
      recipientId,
      sharedDatasets: _datasetIds,
      accessLevel,
      purpose
    });

    // Publish event
    this.eventBus.emit('dataSharingRequest.created', {
      request: submittedRequest,
      agreement
    });

    return submittedRequest;
  }

  /**
   * Approve a data access request
   */
  async approveRequest(
    requestId: string,
    approverId: string,
    approverNotes?: string,
    customDuration?: number // in days, overrides requested duration if provided
  ): Promise<DataAccessGrant> {
    const request = await this.dataAccessService.getRequestById(requestId);
    if (!request) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Request with ID ${requestId} does not exist`,
        { requestId }
      );
    }

    if (request.status !== SharingRequestStatus.SUBMITTED && 
        request.status !== SharingRequestStatus.UNDER_REVIEW) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Request with ID ${requestId} is not in a reviewable status`,
        { requestId, currentStatus: request.status }
      );
    }

    // Verify approver is from the provider institution
    const approverInstitution = await this.getInstitutionByUserId(approverId);
    if (!approverInstitution || approverInstitution.id !== request.dataProviderInstitutionId) {
      throw new DataSharingError(
        'UNAUTHORIZED_ACCESS',
        `User ${approverId} is not authorized to approve this request`,
        { approverId, providerInstitutionId: request.dataProviderInstitutionId }
      );
    }

    // Calculate expiry date based on duration
    const durationInDays = customDuration ?? (request.requestedDuration * 30); // Convert months to approx days
    const expiryDate = new Date();
    expiryDate.setDate(expiryDate.getDate() + durationInDays);

    // Create the grant
    const grant = createDataAccessGrant({
      requestId,
      agreementId: '', // Will be populated by additional logic
      datasetIds: request.requestedDatasets,
      accessLevel: request.requestedAccessLevel,
      purpose: request.researchPurpose,
      status: GrantStatus.ACTIVE,
      approverId,
      approverNotes,
      expiryDate,
      usageConditions: [`Approved for: ${request.projectDescription.substring(0, 100)}...`]
    });

    // Set the institution ID
    grant.institutionId = request.requestingInstitutionId;

    // Create a review decision
    const reviewDecision = {
      decision: 'approved' as const,
      decidedBy: approverId,
      decisionDate: new Date(),
      rationale: approverNotes || 'Request approved',
      conditions: []
    };

    // Update the request status
    const updatedRequest = {
      ...request,
      status: SharingRequestStatus.APPROVED,
      reviewDecision,
      resolvedAt: new Date()
    };

    // Save the updated request
    await this.dataAccessService.updateRequest(updatedRequest);

    // Save the grant
    await this.dataAccessService.saveAccessGrant(grant);

    // Log the approval
    this.logger.info('Data sharing request approved', {
      requestId,
      grantId: grant.id,
      approverId,
      expiryDate
    });

    // Publish events
    this.eventBus.emit('dataSharingRequest.approved', {
      request: updatedRequest,
      grant,
      approverNotes
    });

    this.eventBus.emit('dataAccessGrant.created', {
      grant,
      request: updatedRequest
    });

    return grant;
  }

  /**
   * Reject a data access request
   */
  async rejectRequest(
    requestId: string,
    resolverId: string,
    rejectionReason: string
  ): Promise<DataSharingRequest> {
    const request = await this.dataAccessService.getRequestById(requestId);
    if (!request) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Request with ID ${requestId} does not exist`,
        { requestId }
      );
    }

    if (request.status !== SharingRequestStatus.SUBMITTED && 
        request.status !== SharingRequestStatus.UNDER_REVIEW) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Request with ID ${requestId} is not in a reviewable status`,
        { requestId, currentStatus: request.status }
      );
    }

    // Verify resolver is from the provider institution
    const resolverInstitution = await this.getInstitutionByUserId(resolverId);
    if (!resolverInstitution || resolverInstitution.id !== request.dataProviderInstitutionId) {
      throw new DataSharingError(
        'UNAUTHORIZED_ACCESS',
        `User ${resolverId} is not authorized to reject this request`,
        { resolverId, providerInstitutionId: request.dataProviderInstitutionId }
      );
    }

    // Create a review decision
    const reviewDecision = {
      decision: 'rejected' as const,
      decidedBy: resolverId,
      decisionDate: new Date(),
      rationale: rejectionReason,
      conditions: []
    };

    // Update the request status
    const updatedRequest = {
      ...request,
      status: SharingRequestStatus.REJECTED,
      reviewDecision,
      resolvedAt: new Date()
    };

    // Save the updated request
    await this.dataAccessService.updateRequest(updatedRequest);

    // Log the rejection
    this.logger.info('Data sharing request rejected', {
      requestId,
      resolverId,
      reason: rejectionReason
    });

    // Publish event
    this.eventBus.emit('dataSharingRequest.rejected', {
      request: updatedRequest,
      rejectionReason
    });

    return updatedRequest;
  }

  /**
   * Revoke an active data access grant
   */
  async revokeAccess(
    grantId: string,
    revocationReason: string,
    revokedById: string
  ): Promise<DataAccessGrant> {
    const grant = await this.dataAccessService.getAccessGrantById(grantId);
    if (!grant) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Grant with ID ${grantId} does not exist`,
        { grantId }
      );
    }

    if (!grant.isActive) {
      throw new DataSharingError(
        'INVALID_REQUEST',
        `Grant with ID ${grantId} is not active`,
        { grantId }
      );
    }

    // Update the grant
    const updatedGrant = {
      ...grant,
      isActive: false,
      revocationReason,
      revocationDate: new Date(),
      revokedBy: revokedById
    };

    await this.dataAccessService.updateAccessGrant(updatedGrant);

    // Log the revocation
    this.logger.info('Data access grant revoked', {
      grantId,
      reason: revocationReason
    });

    // Publish event
    this.eventBus.emit('dataAccessGrant.revoked', {
      grant: updatedGrant,
      reason: revocationReason
    });

    return updatedGrant;
  }

