   */
  public getTrainingRoundsByProject(projectId: string): TrainingRound[] {
    return Array.from(this.trainingRounds.values())
      .filter(round => round.projectId === projectId)
      .sort((a, b) => a.roundNumber - b.roundNumber);
  }

