  /**
   * Calculate statistics for the generated dataset
   * Computes statistical measures for numerical fields and correlations
   */
  private calculateDatasetStatistics(dataset: SyntheticDataset): void {
    if (!dataset.records || dataset.records.length === 0) {
      return;
    }
    
    // Identify numeric fields to calculate statistics
    const record = dataset.records[0];
    const numericFields: string[] = [];
    
    for (const [key, value] of Object.entries(record)) {
      if (typeof value === 'number') {
        numericFields.push(key);
      }
    }
    
    // Calculate statistics for each numeric field
    for (const field of numericFields) {
      const values = dataset.records
        .map(r => r[field])
        .filter(v => typeof v === 'number' && !isNaN(v));
      
      if (values.length > 0) {
        const stats = this.calculateStatistics(values);
        dataset.metadata.statistics.fieldStats[field] = stats;
      }
    }
    
    // Calculate correlations between fields
    this.calculateCorrelations(dataset, numericFields);
  }
  
  /**
   * Calculate correlations between numeric fields
   */
  private calculateCorrelations(dataset: SyntheticDataset, numericFields: string[]): void {
    if (numericFields.length < 2) {
      return;
    }
    
    const correlationMatrix: Record<string, Record<string, number>> = {};
    
    // Initialize correlation matrix
    for (const field of numericFields) {
      correlationMatrix[field] = {};
    }
    
    // Calculate pairwise correlations
    for (let i = 0; i < numericFields.length; i++) {
      const field1 = numericFields[i];
      correlationMatrix[field1][field1] = 1.0; // Self-correlation
      
      for (let j = i + 1; j < numericFields.length; j++) {
        const field2 = numericFields[j];
        
        // Get values for both fields
        const pairs: [number, number][] = [];
        
        for (const record of dataset.records) {
          const value1 = record[field1];
          const value2 = record[field2];
          
          if (typeof value1 === 'number' && !isNaN(value1) && 
              typeof value2 === 'number' && !isNaN(value2)) {
            pairs.push([value1, value2]);
          }
        }
        
        // Calculate correlation coefficient (Pearson)
        if (pairs.length > 1) {
          const correlation = this.calculateCorrelationCoefficient(pairs);
          correlationMatrix[field1][field2] = correlation;
          correlationMatrix[field2][field1] = correlation;
        }
      }
    }
    
    dataset.metadata.statistics.correlationMatrix = correlationMatrix;
  }
  
  /**
   * Calculate Pearson correlation coefficient between two variables
   */
  private calculateCorrelationCoefficient(pairs: [number, number][]): number {
    if (pairs.length < 2) {
      return 0;
    }
    
    const n = pairs.length;
    
    // Calculate sums
    let sumX = 0;
    let sumY = 0;
    let sumXY = 0;
    let sumXX = 0;
    let sumYY = 0;
    
    for (const [x, y] of pairs) {
      sumX += x;
      sumY += y;
      sumXY += x * y;
      sumXX += x * x;
      sumYY += y * y;
    }
    
    // Calculate correlation coefficient
    const numerator = n * sumXY - sumX * sumY;
    const denominator = Math.sqrt((n * sumXX - sumX * sumX) * (n * sumYY - sumY * sumY));
    
    if (denominator === 0) {
      return 0;
    }
    
    const correlation = numerator / denominator;
    
    // Round to 3 decimal places
    return parseFloat(correlation.toFixed(3));
  }
  
  /**
   * Generate relationships between students for social network analysis
   * Creates friendship networks and class assignments based on realistic patterns
   * @param dataset The dataset to add relationship data to
   * @param config Configuration settings for the generation process
   * @param random Random number generator function
   */
  private generateRelationships(
    dataset: SyntheticDataset,
    _config: SyntheticDataConfig,
    random: () => number
  ): void {
    if (!dataset.records || dataset.records.length < 2) {
      return;
    }
    
    // Create student classes based on year groups
    const classesByYear: Record<number, string[]> = {};
    
    // Group students by year
    for (const student of dataset.records) {
      const yearGroup = student.yearGroup;
      
      if (!classesByYear[yearGroup]) {
        classesByYear[yearGroup] = [];
      }
      
      classesByYear[yearGroup].push(student.id);
    }
    
    // Create class assignments
    const classAssignments: Record<string, string> = {};
    const classes: Record<string, ClassInfo> = {};
    
    for (const [yearGroup, students] of Object.entries(classesByYear)) {
      // Create classes for this year (avg 25-30 students per class)
      const classSize = 25 + Math.floor(random() * 5);
      const numClasses = Math.max(1, Math.ceil(students.length / classSize));
      
      for (let i = 0; i < numClasses; i++) {
        const className = `${yearGroup}${String.fromCharCode(65 + i)}`; // e.g., 7A, 7B, etc.
        classes[className] = { name: className, students: [] };
      }
      
      // Randomly assign students to classes
      const classNames = Object.keys(classes).filter(name => name.startsWith(yearGroup));
      
      for (const studentId of students) {
        const classIndex = Math.floor(random() * classNames.length);
        const className = classNames[classIndex];
        
        classAssignments[studentId] = className;
        classes[className].students.push(studentId);
      }
    }
    
    // Add class assignments to student records
    for (const student of dataset.records) {
      student.class = classAssignments[student.id];
    }
    
    // Generate friendship relationships
    const friendships: StudentFriendship[] = [];
    
    for (const student of dataset.records) {
      // Students are more likely to be friends with others in the same class
      const classmates = classes[student.class].students.filter(id => id !== student.id);
      
      // Number of friends (follows a roughly normal distribution)
      const numFriends = Math.max(0, Math.floor(this.normalRandom(random, 5, 2)));
      
      // 80% of friends from same class, 20% from same year but different class
      const numClassmateFriends = Math.min(classmates.length, Math.floor(numFriends * 0.8));
      const numOtherFriends = Math.min(
        (classesByYear[student.yearGroup] || []).length - classmates.length - 1,
        numFriends - numClassmateFriends
      );
      
      // Select classmate friends
      const selectedClassmates: string[] = [];
      const remainingClassmates: string[] = [...classmates];
      
      for (let i = 0; i < numClassmateFriends && remainingClassmates.length > 0; i++) {
        const index = Math.floor(random() * remainingClassmates.length);
        selectedClassmates.push(remainingClassmates[index]);
        remainingClassmates.splice(index, 1);
      }
      
      // Select other friends from same year
      const selectedOthers: string[] = [];
      const othersInYear = (classesByYear[student.yearGroup] || [])
        .filter(id => id !== student.id && !classmates.includes(id));
      const remainingOthers: string[] = [...othersInYear];
      
      for (let i = 0; i < numOtherFriends && remainingOthers.length > 0; i++) {
        const index = Math.floor(random() * remainingOthers.length);
        selectedOthers.push(remainingOthers[index]);
        remainingOthers.splice(index, 1);
      }
      
      // Create friendship connections
      for (const friendId of [...selectedClassmates, ...selectedOthers]) {
        // Friendship strength (0.1-1.0)
        const isClassmate = classmates.includes(friendId);
        const baseStrength = isClassmate ? 0.7 : 0.5;
        const strengthVariation = random() * 0.3;
        const strength = parseFloat((baseStrength + strengthVariation).toFixed(2));
        
        friendships.push({
          studentId: student.id,
          friendId,
          strength
        });
      }
    }
    
    // Add friendship relationships to dataset
    if (!dataset.metadata.additionalData) {
      dataset.metadata.additionalData = {};
    }
    
    dataset.metadata.additionalData.relationships = {
      classes,
      friendships
    } as RelationshipData;
  }
}

/**
 * Core data models for the synthetic data generation system
 * 
 * Defines the structures and types used throughout the synthetic data generation
 * process, ensuring type safety and consistency.
 */

/**
 * Types of educational data that can be synthetically generated
 */
export enum SyntheticDataType {
  STUDENT_PERFORMANCE = 'student-performance',
  STUDENT_BEHAVIOR = 'student-behavior',
  TEACHER_ASSESSMENT = 'teacher-assessment',
  SOCIAL_RELATIONSHIPS = 'social-relationships',
  EMOTIONAL_WELLBEING = 'emotional-wellbeing',
  LEARNING_PATTERNS = 'learning-patterns',
  CLASSROOM_DYNAMICS = 'classroom-dynamics',
  PARENTAL_ENGAGEMENT = 'parental-engagement'
}

/**
 * UK-specific educational key stages
 */
export enum UKEducationKeyStage {
  EARLY_YEARS = 'early-years',           // Ages 3-5
  KEY_STAGE_1 = 'key-stage-1',           // Ages 5-7 (Years 1-2)
  KEY_STAGE_2 = 'key-stage-2',           // Ages 7-11 (Years 3-6)
  KEY_STAGE_3 = 'key-stage-3',           // Ages 11-14 (Years 7-9)
  KEY_STAGE_4 = 'key-stage-4',           // Ages 14-16 (Years 10-11)
  KEY_STAGE_5 = 'key-stage-5'            // Ages 16-18 (Years 12-13)
}

/**
 * Demographic distribution models to represent different population structures
 */
export enum DemographicDistribution {
  UK_NATIONAL = 'uk-national',             // Based on UK census data
  LONDON = 'london',                       // London metropolitan demographics
  RURAL = 'rural',                         // Rural UK demographics
  URBAN_DIVERSE = 'urban-diverse',         // Diverse urban setting
  HIGH_NEEDS = 'high-needs',               // Higher proportion of special needs
  CUSTOM = 'custom'                        // User-defined distribution
}

/**
 * Methods for ensuring privacy in synthetic data
 */
export enum PrivacyMethod {
  DIFFERENTIAL_PRIVACY = 'differential-privacy',
  K_ANONYMITY = 'k-anonymity',
  T_CLOSENESS = 't-closeness',
  L_DIVERSITY = 'l-diversity',
  NOISE_ADDITION = 'noise-addition',
  MICROAGGREGATION = 'microaggregation'
}

/**
 * Configuration for generating synthetic data
 */
export interface SyntheticDataConfig {
  /** Type of data to generate */
  dataType: SyntheticDataType;
  
  /** Number of records to generate */
  recordCount: number;
  
  /** Demographic distribution to model */
  demographicDistribution: DemographicDistribution;
  
  /** Custom demographic distribution parameters (if using CUSTOM) */
  customDemographics?: Record<string, any>;
  
  /** UK education key stage to generate data for */
  keyStage?: UKEducationKeyStage;
  
  /** Academic year range for the data */
  academicYearRange?: [number, number];
  
  /** Whether to include special educational needs data */
  includeSpecialEducationalNeeds?: boolean;
  
  /** Privacy method to apply to the generated data */
  privacyMethod?: PrivacyMethod;
  
  /** Whether to generate relationships between entities */
  generateRelationships?: boolean;
  
  /** Random seed for reproducibility */
  seed?: number;
  
  /** Additional parameters specific to the data type */
  additionalParams?: Record<string, any>;
}

/**
 * Metadata about a synthetic dataset
 */
export interface SyntheticDatasetMetadata {
  /** Unique identifier for this dataset */
  id: string;
  
  /** When the dataset was generated */
  generatedAt: Date;
  
  /** Configuration used to generate the data */
  config: SyntheticDataConfig;
  
  /** Statistical summary of the generated data */
  statistics: {
    /** Basic statistical metrics per field */
    fieldStats: Record<string, {
      min?: number;
      max?: number;
      mean?: number;
      median?: number;
      mode?: any;
      stdDev?: number;
      distribution?: string;
    }>;
    
    /** Correlation matrix between fields */
    correlationMatrix?: Record<string, Record<string, number>>;
    
    /** How closely the synthetic data matches target distributions */
    distributionFidelity?: Record<string, number>;
  };
  
  /** Privacy guarantees provided by this dataset */
  privacyGuarantees?: {
    method: PrivacyMethod;
    parameters: Record<string, any>;
    riskMetrics: Record<string, number>;
  };

  /** Additional custom data associated with this dataset */
  additionalData?: Record<string, any>;
}

/**
 * A complete synthetic dataset with data and metadata
 */
export interface SyntheticDataset {
  /** Metadata about this dataset */
  metadata: SyntheticDatasetMetadata;
  
  /** The actual data records */
  records: Record<string, any>[];
  
  /** Schema describing the data structure */
  schema: {
    fields: Array<{
      name: string;
      type: string;
      description?: string;
      constraints?: Record<string, any>;
    }>;
    relationships?: Array<{
      from: string;
      to: string;
      type: string;
      cardinality: string;
    }>;
  };
}

/**
 * Factory function to create a new SyntheticDataConfig with defaults
 */
export function createSyntheticDataConfig(
  params: Partial<SyntheticDataConfig>
): SyntheticDataConfig {
  return {
    dataType: params.dataType || SyntheticDataType.STUDENT_PERFORMANCE,
    recordCount: params.recordCount || 1000,
    demographicDistribution: params.demographicDistribution || DemographicDistribution.UK_NATIONAL,
    keyStage: params.keyStage,
    academicYearRange: params.academicYearRange || [new Date().getFullYear() - 1, new Date().getFullYear()],
    includeSpecialEducationalNeeds: params.includeSpecialEducationalNeeds || false,
    privacyMethod: params.privacyMethod,
    generateRelationships: params.generateRelationships || false,
    seed: params.seed || Math.floor(Math.random() * 1000000),
    additionalParams: params.additionalParams || {},
    customDemographics: params.customDemographics
  };
}

/**
 * Factory function to create an empty synthetic dataset structure
 */
export function createEmptySyntheticDataset(
  config: SyntheticDataConfig,
  schema: any
): SyntheticDataset {
  return {
    metadata: {
      id: `dataset-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
      generatedAt: new Date(),
      config,
      statistics: {
        fieldStats: {}
      },
      additionalData: {}
    },
    records: [],
    schema
  };
}

/**
 * Federated Learning Integration Module
 * 
 * Provides utilities for integrating synthetic data generation with
 * the federated machine learning pipeline, allowing synthetic data
 * to be used for training and evaluation in privacy-preserving
 * federated learning scenarios.
 */

import { SyntheticDataset } from '../models/synthetic-data';
import { applyPrivacyMethods } from './privacy-utils';

/**
 * Configuration for federated learning integration
 */
export interface FederatedIntegrationConfig {
  /** ID of the federated learning project */
  projectId: string;
  
  /** Federated learning round identifier */
  roundId?: string;
  
  /** Percentage of data to use for training (0-1) */
  trainSplit: number;
  
  /** Percentage of data to use for validation (0-1) */
  validationSplit: number;
  
  /** Whether to apply additional privacy transformations */
  applyPrivacy: boolean;
  
  /** Whether to include metadata in the exported data */
  includeMetadata: boolean;
  
  /** Custom transformation function to prepare data for the model */
  transformFn?: (record: any) => any;
}

/**
 * Default federated integration configuration
 */
const DEFAULT_FEDERATED_CONFIG: Partial<FederatedIntegrationConfig> = {
  trainSplit: 0.8,
  validationSplit: 0.2,
  applyPrivacy: true,
  includeMetadata: false
};

/**
 * Prepares a synthetic dataset for use in federated learning
 * @param dataset The synthetic dataset to prepare
 * @param config Configuration for federated learning integration
 * @returns Prepared dataset split into training and validation sets
 */
export function prepareFederatedDataset(
  dataset: SyntheticDataset,
  config: Partial<FederatedIntegrationConfig>
): {
  training: any[];
  validation: any[];
  metadata: any;
} {
  // Merge provided config with defaults
  const fullConfig = { ...DEFAULT_FEDERATED_CONFIG, ...config } as FederatedIntegrationConfig;
  
  if (!fullConfig.projectId) {
    throw new Error('Federated learning project ID is required');
  }
  
  // Apply additional privacy measures if requested
  let processedDataset = dataset;
  if (fullConfig.applyPrivacy && dataset.metadata.privacyGuarantees?.method) {
    processedDataset = applyPrivacyMethods(dataset, {
      method: dataset.metadata.privacyGuarantees.method,
      parameters: dataset.metadata.privacyGuarantees.parameters,
      addMetadata: true
    });
  }
  
  // Shuffle the records for random split
  const shuffledRecords = [...processedDataset.records].sort(() => Math.random() - 0.5);
  
  // Calculate split indices
  const totalRecords = shuffledRecords.length;
  const trainCount = Math.floor(totalRecords * fullConfig.trainSplit);
  const validationCount = Math.floor(totalRecords * fullConfig.validationSplit);
  
  // Split the data
  const trainingRecords = shuffledRecords.slice(0, trainCount);
  const validationRecords = shuffledRecords.slice(trainCount, trainCount + validationCount);
  
  // Apply transformation function if provided
  const transformedTraining = fullConfig.transformFn 
    ? trainingRecords.map(fullConfig.transformFn)
    : trainingRecords;
    
  const transformedValidation = fullConfig.transformFn
    ? validationRecords.map(fullConfig.transformFn)
    : validationRecords;
  
  // Prepare metadata
  const federatedMetadata = {
    projectId: fullConfig.projectId,
    roundId: fullConfig.roundId || `round-${Date.now()}`,
    originalDatasetId: processedDataset.metadata.id,
    trainCount,
    validationCount,
    schema: processedDataset.schema,
    privacyGuarantees: processedDataset.metadata.privacyGuarantees,
    datasetStats: processedDataset.metadata.statistics,
    generatedAt: processedDataset.metadata.generatedAt,
    federatedAt: new Date()
  };
  
  return {
    training: transformedTraining,
    validation: transformedValidation,
    metadata: federatedMetadata
  };
}

